const usersToNotify = [];

for (const item of $input.all()) {
  const user = item.json;

  // Skip if they don't have a time or timezone set
  if (!user.notification_time || !user.timezone) continue;

  try {
    // Get the current hour in the user's specific timezone
    const userLocalTimeStr = new Date().toLocaleString('en-US', {
      timeZone: user.timezone,
      hour12: false,
      hour: 'numeric'
    });

    let userCurrentHour = parseInt(userLocalTimeStr, 10);
    if (userCurrentHour === 24) userCurrentHour = 0;

    // The DB stores time as "18:00:00". Extract the "18".
    const preferenceHour = parseInt(user.notification_time.split(':')[0], 10);

    // Match!
    if (userCurrentHour === preferenceHour) {
      usersToNotify.push(item);
    }
  } catch (e) {
    // Skip if timezone string is invalid
    continue;
  }
}

return usersToNotify;

